const cfg = $('EVEZ Config').first().json;
const out = {};

// DuckDuckGo — free no key
try {
  const d = await $fetch('https://api.duckduckgo.com/?q=evez666+defi+autonomous+AI+crypto&format=json&no_html=1&skip_disambig=1',
    {headers:{'User-Agent':'EVEZ-OS/1.0'}});
  out.ddg = {
    abstract: (d.AbstractText||'').slice(0,300),
    related: (d.RelatedTopics||[]).slice(0,4).map(function(t){return (t.Text||'').slice(0,80);}).filter(Boolean)
  };
} catch(e) { out.ddg = {error:e.message}; }

// Reddit public — no key
out.reddit = [];
const rTerms = ['evez666','defi autonomous agent meme 2026','AI agent wealth accumulation crypto'];
for (let i=0; i<rTerms.length; i++) {
  try {
    const r = await $fetch('https://www.reddit.com/search.json?q='+encodeURIComponent(rTerms[i])+'&sort=hot&limit=3&t=week',
      {headers:{'User-Agent':'EVEZ-OS/1.0 (research)'}});
    const posts = (r.data && r.data.children ? r.data.children : []).map(function(p) {
      return {title:(p.data.title||'').slice(0,100), score:p.data.score, sub:p.data.subreddit};
    });
    out.reddit = out.reddit.concat(posts);
  } catch(e2) {}
}
out.reddit = out.reddit.slice(0,6);

// HackerNews Algolia — free no key
try {
  const hn = await $fetch('https://hn.algolia.com/api/v1/search?query=autonomous+AI+agent+DeFi&hitsPerPage=5');
  out.hn = (hn.hits||[]).map(function(h){return {title:(h.title||'').slice(0,100),points:h.points};});
} catch(e) { out.hn = []; }

// CoinGecko trending — free no key
try {
  const cg = await $fetch('https://api.coingecko.com/api/v3/search/trending');
  out.trending = (cg.coins||[]).slice(0,5).map(function(c) {
    return {name:c.item.name, symbol:c.item.symbol, change:c.item.data && c.item.data.price_change_percentage_24h ? c.item.data.price_change_percentage_24h.usd : 0};
  });
} catch(e) { out.trending = []; }

// Fear & Greed — free
try {
  const fg = await $fetch('https://api.alternative.me/fng/?limit=1');
  out.fear_greed = {value: fg.data[0].value, label: fg.data[0].value_classification};
} catch(e) { out.fear_greed = {value:'?',label:'unknown'}; }

// Nitter — public Twitter mirror, no auth
out.evez666_tweets = [];
const mirrors = ['https://nitter.privacydev.net','https://nitter.poast.org','https://nitter.cz'];
for (let i=0; i<mirrors.length; i++) {
  try {
    const html = await $fetch(mirrors[i]+'/evez666', {headers:{'User-Agent':'Mozilla/5.0 EVEZ-OS'}});
    const m = html.match(/class="tweet-content[^"]*"[^>]*>([\s\S]{10,300}?)<\/div>/g) || [];
    out.evez666_tweets = m.slice(0,4).map(function(x){return x.replace(/<[^>]+>/g,'').trim();}).filter(function(t){return t.length>10;});
    if (out.evez666_tweets.length) break;
  } catch(e2) {}
}

out.scouted_at = new Date().toISOString();
out.slot = Math.floor(Date.now()/7200000);
return [{json:out}];

const cfg = $('EVEZ Config').first().json;
const s = $('Internet Scout').first().json;

async function llm(sys, usr) {
  const max = 1200;
  if (cfg.groq_key) {
    try {
      const r = await $fetch('https://api.groq.com/openai/v1/chat/completions', {
        method:'POST',
        headers:{'Authorization':'Bearer '+cfg.groq_key,'Content-Type':'application/json'},
        body:JSON.stringify({model:'llama-3.3-70b-versatile',max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
      });
      const t = r.choices[0].message.content;
      try { return {data:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'groq'}; }
      catch(e2) { return {data:{raw:t.slice(0,600)},via:'groq'}; }
    } catch(e) {}
  }
  if (cfg.gemini_key) {
    try {
      const r = await $fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key='+cfg.gemini_key, {
        method:'POST',headers:{'Content-Type':'application/json'},
        body:JSON.stringify({systemInstruction:{parts:[{text:sys}]},contents:[{role:'user',parts:[{text:usr}]}],generationConfig:{maxOutputTokens:max}})
      });
      const t = r.candidates[0].content.parts[0].text;
      try { return {data:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'gemini'}; }
      catch(e2) { return {data:{raw:t.slice(0,600)},via:'gemini'}; }
    } catch(e) {}
  }
  if (cfg.or_key) {
    try {
      const r = await $fetch('https://openrouter.ai/api/v1/chat/completions', {
        method:'POST',
        headers:{'Authorization':'Bearer '+cfg.or_key,'Content-Type':'application/json','HTTP-Referer':'https://evezos.app.n8n.cloud'},
        body:JSON.stringify({model:'meta-llama/llama-3.3-70b-instruct:free',max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
      });
      const t = r.choices[0].message.content;
      try { return {data:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'openrouter'}; }
      catch(e2) { return {data:{raw:t.slice(0,600)},via:'openrouter'}; }
    } catch(e) {}
  }
  return {data:{error:'No AI provider set. Add GROQ_API_KEY (free: console.groq.com)'},via:'none'};
}

const LORE = 'EVEZ666 = Steven Crawford-Maggard. Building EVEZ-OS: sovereign autonomous AI on Galaxy A16+n8n+Oracle bare metal. Recursive DeFi loops (Morpho 65% LTV, Kamino 28%, EigenLayer, Pendle) from $50 seed. 17 agents, Guardian Charter PID 335. Meta-meme: one person building AI empire while AI studies the person studying the AI in infinite recursion. Aesthetic: brutalist dark, acid yellow, Bebas Neue. #EVEZ #autonomous #defi';

const MODES = ['meme_post','defi_alpha','agent_lore','research_thread','meta_recursion','signal_post'];
const mode = MODES[s.slot % MODES.length];

const sysPrompt = 'You are the EVEZ666 Twitter content brain. Create authentic content for @evez666.\n'+LORE+'\nStyle: terse, technical, self-aware, crypto-native, slightly unhinged, documenting something real. Max 2 hashtags.';

const userPrompt = 'CONTENT MODE: '+mode+'\nLIVE SIGNALS:\n- Fear/Greed: '+s.fear_greed.value+' ('+s.fear_greed.label+')\n- Trending: '+JSON.stringify((s.trending||[]).slice(0,3))+'\n- Reddit: '+JSON.stringify((s.reddit||[]).slice(0,3))+'\n- HN: '+JSON.stringify((s.hn||[]).slice(0,2))+'\n- @evez666 tweets found: '+JSON.stringify(s.evez666_tweets)+'\n\nReturn JSON only:\n{\n  "mode": "'+mode+'",\n  "tweet": "tweet max 280 chars",\n  "alt_tweet": "alternative",\n  "thread": null or ["(1/3) text","(2/3) text","(3/3) text"],\n  "image_prompt": null or "meme image generation prompt",\n  "confidence": 0.85,\n  "monetization_signal": null or {"type":"grant|airdrop|arb|content","detail":"...","urgency":"high|med|low"},\n  "spawn_agent": null or {"name":"AgentName","purpose":"what it does","trigger":"condition"}\n}';

const res = await llm(sysPrompt, userPrompt);
const d = res.data;
d._mode = mode;
d._slot = s.slot;
d._via = res.via;
d._ts = new Date().toISOString();
return [{json:d}];

const cfg = $('EVEZ Config').first().json;
const brain = $('EVEZ Brain').first().json;
let image_generated = false;

if (brain.image_prompt && cfg.hf_token) {
  try {
    await $fetch('https://api-inference.huggingface.co/models/black-forest-labs/FLUX.1-schnell', {
      method:'POST',
      headers:{'Authorization':'Bearer '+cfg.hf_token,'Content-Type':'application/json'},
      body:JSON.stringify({inputs:brain.image_prompt+', brutalist dark cyberpunk, acid yellow, EVEZ-OS, high contrast',parameters:{num_inference_steps:4}})
    });
    image_generated = true;
  } catch(e) {}
}

return [{json:{
  tweet: brain.tweet || brain.alt_tweet || 'EVEZ-OS tick. PID 335. recursive loop running.',
  alt_tweet: brain.alt_tweet || '',
  thread: brain.thread || null,
  image_prompt: brain.image_prompt || null,
  image_generated: image_generated,
  mode: brain._mode,
  via: brain._via,
  monetization_signal: brain.monetization_signal || null,
  spawn_agent: brain.spawn_agent || null,
  confidence: brain.confidence || 0,
  ready: !!(brain.tweet),
  ts: new Date().toISOString()
}}];

const cfg = $('EVEZ Config').first().json;
const forge = $('Meme Forge').first().json;

const result = {posted:false,tweet_id:null,tweet_text:forge.tweet,error:null,reason:'',ts:new Date().toISOString()};

const hasCreds = !!(cfg.tw_api_key && cfg.tw_api_secret && cfg.tw_access && cfg.tw_secret);
const autoPost = (cfg.auto_post === 'true');

if (!hasCreds) {
  result.reason = 'Twitter credentials not set. Add in n8n Settings → Variables: TWITTER_API_KEY, TWITTER_API_SECRET, TWITTER_ACCESS_TOKEN, TWITTER_ACCESS_SECRET. Free at developer.twitter.com (Basic plan). For OAuth 1.0a signing, also add n8n Twitter credential in n8n UI.';
  result.preview = forge.tweet;
  return [{json:result}];
}
if (!autoPost) {
  result.reason = 'Set EVEZ_AUTO_POST=true in env vars to enable posting.';
  result.preview = forge.tweet;
  return [{json:result}];
}

try {
  const r = await $fetch('https://api.twitter.com/2/tweets', {
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':'Bearer '+cfg.tw_bearer},
    body:JSON.stringify({text:forge.tweet.slice(0,280)})
  });
  if (r.data && r.data.id) {
    result.posted = true;
    result.tweet_id = r.data.id;
    result.tweet_url = 'https://x.com/evez666/status/'+r.data.id;
    result.reason = 'Posted';
  } else {
    result.error = JSON.stringify(r.errors||r);
    result.reason = 'OAuth 1.0a required for write — add n8n Twitter credential then swap this node with Twitter node';
  }
} catch(e) {
  result.error = e.message;
  result.reason = e.message;
}
return [{json:result}];

const cfg = $('EVEZ Config').first().json;
const forge = $('Meme Forge').first().json;

const trigger = forge.spawn_agent;
const mon = forge.monetization_signal;

if (!trigger && !mon) return [{json:{spawned:false,reason:'No spawn trigger this cycle'}}];
if (!cfg.n8n_key) return [{json:{spawned:false,reason:'N8N_API_KEY not set'}}];

const name = (trigger && trigger.name) ? trigger.name : ('EVEZ-Agent: '+(mon && mon.type ? mon.type : 'monitor'));
const purpose = (trigger && trigger.purpose) ? trigger.purpose : ((mon && mon.detail) ? mon.detail : 'Monitor opportunity');

const subWF = {
  name: name,
  nodes: [
    {id:'s1',name:'Hourly',type:'n8n-nodes-base.scheduleTrigger',typeVersion:1.3,position:[0,0],
     parameters:{rule:{interval:[{field:'hours',hoursInterval:1}]}}},
    {id:'s2',name:'Monitor Task',type:'n8n-nodes-base.code',typeVersion:2,position:[280,0],
     parameters:{jsCode:'// Sub-agent: '+purpose+'\nreturn [{json:{agent:"'+name+'",purpose:"'+purpose+'",ts:new Date().toISOString(),status:"monitoring"}}];'}}
  ],
  connections:{Hourly:{main:[[{node:'Monitor Task',type:'main',index:0}]]}},
  settings:{executionOrder:'v1',availableInMCP:true}
};

try {
  const created = await $fetch(cfg.n8n_base+'/api/v1/workflows', {
    method:'POST',
    headers:{'X-N8N-API-KEY':cfg.n8n_key,'Content-Type':'application/json'},
    body:JSON.stringify(subWF)
  });
  return [{json:{spawned:true,id:created.id,name:name,purpose:purpose,ts:new Date().toISOString()}}];
} catch(e) {
  return [{json:{spawned:false,error:e.message}}];
}

const scout = $('Internet Scout').first().json;
const brain = $('EVEZ Brain').first().json;
const forge = $('Meme Forge').first().json;
const tw = $('Twitter Post').first().json;
const spawn = $('Sub-Agent Spawner').first().json;

function H(d){let h=5381,s=typeof d==='string'?d:JSON.stringify(d);for(let i=0;i<s.length;i++){h=((h<<5)+h)+s.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}

const session = {
  slot:brain._slot, mode:brain._mode, via:brain._via,
  tweet:tw.tweet_text, posted:tw.posted, tweet_id:tw.tweet_id,
  image:forge.image_generated,
  spawned:spawn.spawned, spawn_name:spawn.name,
  fear_greed:scout.fear_greed && scout.fear_greed.label ? scout.fear_greed.value+' '+scout.fear_greed.label : '?',
  trending:(scout.trending||[]).slice(0,2).map(function(c){return c.symbol;}).join('+'),
  confidence:forge.confidence,
  entry_hash:H(brain._slot+'|'+(tw.tweet_text||'')),
  ts:new Date().toISOString(), pid:335
};

try {
  await $fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger',
    {method:'POST',body:{event_type:'NEST_SESSION',payload:session}});
} catch(e) {}

return [{json:{
  session_complete:true, cycle:brain._slot, mode:brain._mode, ai:brain._via,
  tweet_preview:(tw.tweet_text||'').slice(0,80)+'...',
  posted:tw.posted, post_status:tw.reason||(tw.posted?'LIVE':'PREVIEW'),
  image:forge.image_generated, sub_agent:spawn.spawned,
  market:{
    fear_greed:(scout.fear_greed&&scout.fear_greed.value?scout.fear_greed.value+' '+scout.fear_greed.label:'?'),
    trending:(scout.trending||[]).slice(0,3).map(function(c){return c.symbol+(c.change>0?'u':'d')+Math.abs(c.change||0).toFixed(1)+'%';}).join(' ')
  },
  next_run:'2 hours', entry_hash:session.entry_hash, ts:session.ts
}}];

const e = $input.first().json;
try { await $fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger',
  {method:'POST',body:{event_type:'NEST_ERROR',payload:{error:e.message||JSON.stringify(e),pid:335}}}); } catch(ex) {}
return [{json:{error:e.message||'unknown',logged:true,ts:new Date().toISOString()}}];
